package main.rice.obj;

/**
 * Abstract base for iterable objects.
 * @param <T> the type of the underlying collection.
 */
public abstract class AIterablePyObj<T> extends APyObj<T> {
}

package main.rice.obj;

import java.util.List;

/**
 * List objects.
 * @param <E> the type of elements in the list.
 */
public class PyListObj<E extends APyObj<?>> extends AIterablePyObj<List<E>> {

    /**
     * Constructor for PyListObj.
     * @param value the underlying Java List of elements.
     */
    public PyListObj(List<E> value) {
        this.value = value;
    }

    /**
     * Returns a Python-style string representation.
     * @return the list surrounded by square brackets.
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("[");
        for (int i = 0; i < this.value.size(); i++) {
            sb.append(this.value.get(i).toString());
            if (i < this.value.size() - 1) {
                sb.append(", ");
            }
        }
        sb.append("]");
        return sb.toString();
    }
}

package main.rice.obj;

import java.util.List;

/**
 * Tuple objects.
 * @param <E> the type of elements in the tuple.
 */
public class PyTupleObj<E extends APyObj<?>> extends AIterablePyObj<List<E>> {

    /**
     * Constructor for PyTupleObj.
     * @param value the underlying Java List of elements.
     */
    public PyTupleObj(List<E> value) {
        this.value = value;
    }

    /**
     * Returns a Python-style string representation.
     * @return the tuple surrounded by parentheses.
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("(");
        for (int i = 0; i < this.value.size(); i++) {
            sb.append(this.value.get(i).toString());
            if (i < this.value.size() - 1) {
                sb.append(", ");
            }
        }
        if (this.value.size() == 1) {
            sb.append(",");
        }
        sb.append(")");
        return sb.toString();
    }
}

package main.rice.obj;

import java.util.Iterator;
import java.util.Set;

/**
 * Set objects.
 * @param <E> the type of elements in the set.
 */
public class PySetObj<E extends APyObj<?>> extends AIterablePyObj<Set<E>> {

    /**
     * Constructor for PySetObj.
     * @param value the underlying Java Set of elements.
     */
    public PySetObj(Set<E> value) {
        this.value = value;
    }

    /**
     * Returns a Python-style string representation.
     * @return "set()" if empty, or the set elements surrounded by curly braces.
     */
    @Override
    public String toString() {
        if (this.value.isEmpty()) {
            return "set()";
        }
        StringBuilder sb = new StringBuilder("{");
        Iterator<E> it = this.value.iterator();
        while (it.hasNext()) {
            sb.append(it.next().toString());
            if (it.hasNext()) {
                sb.append(", ");
            }
        }
        sb.append("}");
        return sb.toString();
    }
}

package main.rice.obj;

import java.util.Iterator;
import java.util.Map;

/**
 * Dictionary objects.
 * @param <K> the type of keys in the dict.
 * @param <V> the type of values in the dict.
 */
public class PyDictObj<K extends APyObj<?>, V extends APyObj<?>> extends AIterablePyObj<Map<K, V>> {

    /**
     * Constructor for PyDictObj.
     * @param value the underlying Java Map of key-value pairs.
     */
    public PyDictObj(Map<K, V> value) {
        this.value = value;
    }

    /**
     * Returns a Python-style string representation.
     * @return the dict surrounded by curly braces with key: value pairs.
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("{");
        Iterator<Map.Entry<K, V>> it = this.value.entrySet().iterator();
        while (it.hasNext()) {
            Map.Entry<K, V> entry = it.next();
            sb.append(entry.getKey().toString());
            sb.append(": ");
            sb.append(entry.getValue().toString());
            if (it.hasNext()) {
                sb.append(", ");
            }
        }
        sb.append("}");
        return sb.toString();
    }
}

package main.rice.obj;

import java.util.ArrayList;
import java.util.List;

/**
 * String objects.
 */
public class PyStringObj extends AIterablePyObj<List<PyCharObj>> {

    /**
     * Constructor for PyStringObj.
     * @param value the underlying Java String value.
     */
    public PyStringObj(String value) {
        this.value = new ArrayList<>();
        for (char c : value.toCharArray()) {
            this.value.add(new PyCharObj(c));
        }
    }

    /**
     * Returns a Python-style string representation.
     * @return the string surrounded by single quotes.
     */
    @Override
    public String toString() {
        StringBuilder sb = new StringBuilder("'");
        for (PyCharObj c : this.value) {
            // Note: PyCharObj.getValue() returns the Character.
            // We don't want the quotes from PyCharObj.toString().
            sb.append(c.getValue());
        }
        sb.append("'");
        return sb.toString();
    }
}

