package test.rice.obj;

import main.rice.obj.*;
import org.junit.jupiter.api.*;
import java.util.*;
import static org.junit.jupiter.api.Assertions.*;

/**
 * Additional test cases for all PyObj classes.
 */
class PyObjTest {

    @Test
    void testPyIntObj() {
        PyIntObj i = new PyIntObj(42);
        assertEquals(42, i.getValue());
        assertEquals("42", i.toString());
        assertEquals(new PyIntObj(42), i);
        assertNotEquals(new PyIntObj(43), i);
        assertEquals(new PyIntObj(42).hashCode(), i.hashCode());
    }

    @Test
    void testPyFloatObj() {
        PyFloatObj f = new PyFloatObj(3.14);
        assertEquals(3.14, f.getValue());
        assertEquals("3.14", f.toString());
        assertEquals(new PyFloatObj(3.14), f);
        assertNotEquals(new PyFloatObj(2.71), f);
        assertEquals(new PyFloatObj(3.14).hashCode(), f.hashCode());
    }

    @Test
    void testPyBoolObj() {
        PyBoolObj trueObj = new PyBoolObj(true);
        PyBoolObj falseObj = new PyBoolObj(false);
        assertEquals(true, trueObj.getValue());
        assertEquals(false, falseObj.getValue());
        assertEquals("True", trueObj.toString());
        assertEquals("False", falseObj.toString());
        assertEquals(new PyBoolObj(true), trueObj);
        assertNotEquals(trueObj, falseObj);
    }

    @Test
    void testPyCharObj() {
        PyCharObj c = new PyCharObj('a');
        assertEquals('a', c.getValue());
        assertEquals("'a'", c.toString());
        assertEquals(new PyCharObj('a'), c);
        assertNotEquals(new PyCharObj('b'), c);
    }

    @Test
    void testEqualsDifferentTypes() {
        PyIntObj i = new PyIntObj(1);
        PyFloatObj f = new PyFloatObj(1.0);
        assertNotEquals(i, f);
        assertNotEquals(f, i);
    }

    @Test
    void testPyStringObjEquals() {
        PyStringObj s1 = new PyStringObj("hello");
        PyStringObj s2 = new PyStringObj("hello");
        PyStringObj s3 = new PyStringObj("world");
        assertEquals(s1, s2);
        assertNotEquals(s1, s3);
        assertEquals(s1.hashCode(), s2.hashCode());
    }

    @Test
    void testPyDictObjEquals() {
        Map<PyIntObj, PyStringObj> m1 = new LinkedHashMap<>();
        m1.put(new PyIntObj(1), new PyStringObj("a"));
        PyDictObj<PyIntObj, PyStringObj> d1 = new PyDictObj<>(m1);

        Map<PyIntObj, PyStringObj> m2 = new LinkedHashMap<>();
        m2.put(new PyIntObj(1), new PyStringObj("a"));
        PyDictObj<PyIntObj, PyStringObj> d2 = new PyDictObj<>(m2);

        Map<PyIntObj, PyStringObj> m3 = new LinkedHashMap<>();
        m3.put(new PyIntObj(1), new PyStringObj("b"));
        PyDictObj<PyIntObj, PyStringObj> d3 = new PyDictObj<>(m3);

        assertEquals(d1, d2);
        assertNotEquals(d1, d3);
        assertEquals(d1.hashCode(), d2.hashCode());
    }
}
